CREATE SCHEMA IF NOT EXISTS document;

CREATE OR REPLACE FUNCTION document.brand()
 RETURNS text
 LANGUAGE plpgsql
AS $function$
BEGIN
  RETURN pgv.t('document.brand');
END;
$function$;
COMMENT ON FUNCTION document.brand() IS 'Brand name for document module (i18n)';

CREATE OR REPLACE FUNCTION document.canvas_clear(p_canvas_id uuid)
 RETURNS integer
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_count int;
BEGIN
  DELETE FROM document.element
  WHERE canvas_id = p_canvas_id
    AND tenant_id = current_setting('app.tenant_id', true);
  GET DIAGNOSTICS v_count = ROW_COUNT;
  RETURN v_count;
END;
$function$;
COMMENT ON FUNCTION document.canvas_clear(uuid) IS 'Remove all elements from a canvas';

CREATE OR REPLACE FUNCTION document.canvas_create(p_name text, p_format text DEFAULT 'A4'::text, p_orientation text DEFAULT 'portrait'::text, p_width real DEFAULT NULL::real, p_height real DEFAULT NULL::real, p_bg text DEFAULT '#ffffff'::text, p_category text DEFAULT 'general'::text)
 RETURNS uuid
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_w real := p_width;
  v_h real := p_height;
  v_id uuid;
BEGIN
  -- Default dimensions by format (mm -> px at 96dpi ≈ 3.78px/mm)
  IF v_w IS NULL OR v_h IS NULL THEN
    CASE p_format
      WHEN 'A2' THEN v_w := 1587; v_h := 2245;
      WHEN 'A3' THEN v_w := 1123; v_h := 1587;
      WHEN 'A4' THEN v_w := 794;  v_h := 1123;
      WHEN 'A5' THEN v_w := 559;  v_h := 794;
      WHEN 'HD' THEN v_w := 1920; v_h := 1080;
      WHEN 'MACBOOK' THEN v_w := 1440; v_h := 900;
      WHEN 'IPAD' THEN v_w := 1024; v_h := 1366;
      WHEN 'MOBILE' THEN v_w := 390; v_h := 844;
      ELSE v_w := 794; v_h := 1123; -- default A4
    END CASE;
  END IF;

  -- Swap for landscape
  IF p_orientation = 'paysage' AND v_w < v_h THEN
    v_w := v_w + v_h;
    v_h := v_w - v_h;
    v_w := v_w - v_h;
  END IF;

  INSERT INTO document.canvas (name, format, orientation, width, height, background, category)
  VALUES (p_name, p_format, p_orientation, v_w, v_h, p_bg, p_category)
  RETURNING id INTO v_id;

  RETURN v_id;
END;
$function$;
COMMENT ON FUNCTION document.canvas_create(text,text,text,real,real,text,text) IS 'Create a canvas with format-based default dimensions';

CREATE OR REPLACE FUNCTION document.canvas_duplicate(p_source_id uuid, p_new_name text)
 RETURNS uuid
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_new_id uuid;
  v_src document.canvas;
  v_map jsonb := '{}'; -- old_id -> new_id mapping
  r record;
  v_new_elem_id uuid;
  v_new_parent uuid;
BEGIN
  -- Copy canvas
  SELECT * INTO v_src FROM document.canvas
  WHERE id = p_source_id AND tenant_id = current_setting('app.tenant_id', true);

  IF v_src IS NULL THEN
    RAISE EXCEPTION 'Canvas not found: %', p_source_id;
  END IF;

  INSERT INTO document.canvas (name, format, orientation, width, height, background, category, meta, template_id)
  VALUES (p_new_name, v_src.format, v_src.orientation, v_src.width, v_src.height, v_src.background, v_src.category, v_src.meta, v_src.template_id)
  RETURNING id INTO v_new_id;

  -- Copy gradients
  INSERT INTO document.gradient (canvas_id, type, angle, cx, cy, gr, stops)
  SELECT v_new_id, g.type, g.angle, g.cx, g.cy, g.gr, g.stops
  FROM document.gradient g WHERE g.canvas_id = p_source_id;

  -- Copy elements (parents first via sort on parent_id nulls first)
  FOR r IN
    SELECT * FROM document.element
    WHERE canvas_id = p_source_id
    ORDER BY parent_id NULLS FIRST, sort_order
  LOOP
    v_new_parent := NULL;
    IF r.parent_id IS NOT NULL THEN
      v_new_parent := (v_map->>r.parent_id::text)::uuid;
    END IF;

    INSERT INTO document.element (
      canvas_id, type, parent_id, sort_order, name,
      x, y, width, height, x1, y1, x2, y2, cx, cy, r, rx_, ry_,
      opacity, rotation, fill, stroke, stroke_width, stroke_dasharray,
      props, asset_id
    ) VALUES (
      v_new_id, r.type, v_new_parent, r.sort_order, r.name,
      r.x, r.y, r.width, r.height, r.x1, r.y1, r.x2, r.y2, r.cx, r.cy, r.r, r.rx_, r.ry_,
      r.opacity, r.rotation, r.fill, r.stroke, r.stroke_width, r.stroke_dasharray,
      r.props, r.asset_id
    ) RETURNING id INTO v_new_elem_id;

    v_map := v_map || jsonb_build_object(r.id::text, v_new_elem_id);
  END LOOP;

  RETURN v_new_id;
END;
$function$;
COMMENT ON FUNCTION document.canvas_duplicate(uuid,text) IS 'Deep copy canvas with all elements (new UUIDs, parent mapping)';

CREATE OR REPLACE FUNCTION document.canvas_render_svg_mini(p_canvas_id uuid)
 RETURNS text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_c document.canvas;
  v_svg text;
  v_defs text := '';
  v_attrs text;
  v_transform text;
  v_cx real; v_cy real;
  v_img_path text;
  v_img_mime text;
  v_object_fit text;
  v_nat_w real; v_nat_h real;
  v_crop_x real; v_crop_y real; v_crop_zoom real;
  v_base_scale real; v_scale real;
  v_img_w real; v_img_h real; v_img_x real; v_img_y real;
  r record;
BEGIN
  SELECT * INTO v_c FROM document.canvas WHERE id = p_canvas_id;
  IF v_c IS NULL THEN RETURN NULL; END IF;

  v_svg := '';
  v_svg := v_svg || '<rect width="' || v_c.width::text || '" height="' || v_c.height::text
    || '" fill="' || pgv.esc(v_c.background) || '"/>';

  FOR r IN
    SELECT * FROM document.element
    WHERE canvas_id = p_canvas_id
    ORDER BY sort_order
  LOOP
    v_attrs := '';
    IF r.opacity < 1 THEN v_attrs := v_attrs || ' opacity="' || r.opacity::text || '"'; END IF;
    IF r.stroke_dasharray IS NOT NULL THEN v_attrs := v_attrs || ' stroke-dasharray="' || pgv.esc(r.stroke_dasharray) || '"'; END IF;
    IF r.stroke_width IS NOT NULL THEN v_attrs := v_attrs || ' stroke-width="' || r.stroke_width::text || '"'; END IF;

    v_transform := '';
    IF r.rotation != 0 THEN
      CASE r.type
        WHEN 'rect', 'image', 'text' THEN
          v_cx := COALESCE(r.x, 0) + COALESCE(r.width, 0) / 2;
          v_cy := COALESCE(r.y, 0) + COALESCE(r.height, 0) / 2;
        WHEN 'circle' THEN v_cx := r.cx; v_cy := r.cy;
        WHEN 'ellipse' THEN v_cx := r.cx; v_cy := r.cy;
        WHEN 'line' THEN v_cx := (r.x1 + r.x2) / 2; v_cy := (r.y1 + r.y2) / 2;
        ELSE v_cx := 0; v_cy := 0;
      END CASE;
      v_transform := ' transform="rotate(' || r.rotation::text || ',' || v_cx::text || ',' || v_cy::text || ')"';
    END IF;

    CASE r.type
      WHEN 'rect' THEN
        v_svg := v_svg || '<rect x="' || r.x::text || '" y="' || r.y::text
          || '" width="' || r.width::text || '" height="' || r.height::text || '"'
          || CASE WHEN r.fill IS NOT NULL THEN ' fill="' || pgv.esc(r.fill) || '"' ELSE '' END
          || CASE WHEN r.stroke IS NOT NULL THEN ' stroke="' || pgv.esc(r.stroke) || '"' ELSE '' END
          || CASE WHEN r.rx_ IS NOT NULL THEN ' rx="' || r.rx_::text || '"' ELSE '' END
          || CASE WHEN (r.props->>'borderRadius') IS NOT NULL THEN ' rx="' || pgv.esc(r.props->>'borderRadius') || '"' ELSE '' END
          || v_attrs || v_transform || '/>';
      WHEN 'text' THEN
        v_svg := v_svg || '<text x="' || r.x::text || '" y="' || r.y::text || '"'
          || CASE WHEN r.fill IS NOT NULL THEN ' fill="' || pgv.esc(r.fill) || '"' ELSE '' END
          || ' font-size="' || COALESCE((r.props->>'fontSize')::text, '12') || '"'
          || CASE WHEN r.props->>'fontWeight' = 'bold' THEN ' font-weight="bold"' ELSE '' END
          || CASE WHEN r.props->>'fontStyle' = 'italic' THEN ' font-style="italic"' ELSE '' END
          || CASE WHEN r.props->>'textAnchor' IS NOT NULL THEN ' text-anchor="' || pgv.esc(r.props->>'textAnchor') || '"' ELSE '' END
          || v_attrs || v_transform
          || '>' || pgv.esc(COALESCE(r.props->>'content', '')) || '</text>';
      WHEN 'line' THEN
        v_svg := v_svg || '<line x1="' || r.x1::text || '" y1="' || r.y1::text
          || '" x2="' || r.x2::text || '" y2="' || r.y2::text || '"'
          || ' stroke="' || COALESCE(pgv.esc(r.stroke), '#000') || '"'
          || v_attrs || v_transform || '/>';
      WHEN 'circle' THEN
        v_svg := v_svg || '<circle cx="' || r.cx::text || '" cy="' || r.cy::text
          || '" r="' || r.r::text || '"'
          || CASE WHEN r.fill IS NOT NULL THEN ' fill="' || pgv.esc(r.fill) || '"' ELSE '' END
          || CASE WHEN r.stroke IS NOT NULL THEN ' stroke="' || pgv.esc(r.stroke) || '"' ELSE '' END
          || v_attrs || v_transform || '/>';
      WHEN 'ellipse' THEN
        v_svg := v_svg || '<ellipse cx="' || r.cx::text || '" cy="' || r.cy::text
          || '" rx="' || r.rx_::text || '" ry="' || r.ry_::text || '"'
          || CASE WHEN r.fill IS NOT NULL THEN ' fill="' || pgv.esc(r.fill) || '"' ELSE '' END
          || CASE WHEN r.stroke IS NOT NULL THEN ' stroke="' || pgv.esc(r.stroke) || '"' ELSE '' END
          || v_attrs || v_transform || '/>';
      WHEN 'image' THEN
        v_img_path := NULL;
        v_img_mime := NULL;
        IF r.asset_id IS NOT NULL THEN
          SELECT a.path, a.mime_type INTO v_img_path, v_img_mime FROM asset.asset a WHERE a.id = r.asset_id;
        END IF;
        IF v_img_path IS NOT NULL THEN
          v_object_fit := COALESCE(r.props->>'objectFit', 'cover');

          IF v_img_mime = 'image/svg+xml' OR v_object_fit = 'contain' THEN
            -- SVG or contain: preserve aspect ratio, no crop
            v_svg := v_svg || '<image href="' || pgv.esc(v_img_path) || '"'
              || ' x="' || r.x::text || '" y="' || r.y::text
              || '" width="' || r.width::text || '" height="' || r.height::text || '"'
              || ' preserveAspectRatio="xMidYMid meet"'
              || v_attrs || v_transform || '/>';
          ELSIF r.props->>'naturalWidth' IS NOT NULL THEN
            -- Crop cover with clipPath
            v_nat_w := (r.props->>'naturalWidth')::real;
            v_nat_h := (r.props->>'naturalHeight')::real;
            v_crop_x := COALESCE((r.props->>'cropX')::real, 0.5);
            v_crop_y := COALESCE((r.props->>'cropY')::real, 0.5);
            v_crop_zoom := COALESCE((r.props->>'cropZoom')::real, 1.0);
            v_base_scale := greatest(r.width / v_nat_w, r.height / v_nat_h);
            v_scale := v_base_scale * v_crop_zoom;
            v_img_w := v_nat_w * v_scale;
            v_img_h := v_nat_h * v_scale;
            v_img_x := r.x - (v_img_w - r.width) * v_crop_x;
            v_img_y := r.y - (v_img_h - r.height) * v_crop_y;

            v_defs := v_defs || '<clipPath id="c_' || r.id::text || '">'
              || '<rect x="' || r.x::text || '" y="' || r.y::text
              || '" width="' || r.width::text || '" height="' || r.height::text || '"/>'
              || '</clipPath>';

            v_svg := v_svg || '<g clip-path="url(#c_' || r.id::text || ')"' || v_attrs || v_transform || '>'
              || '<image href="' || pgv.esc(v_img_path) || '"'
              || ' x="' || v_img_x::text || '" y="' || v_img_y::text
              || '" width="' || v_img_w::text || '" height="' || v_img_h::text
              || '" preserveAspectRatio="none"/></g>';
          ELSE
            -- Fallback: slice
            v_svg := v_svg || '<image href="' || pgv.esc(v_img_path) || '"'
              || ' x="' || r.x::text || '" y="' || r.y::text
              || '" width="' || r.width::text || '" height="' || r.height::text || '"'
              || ' preserveAspectRatio="xMidYMid slice"'
              || v_attrs || v_transform || '/>';
          END IF;
        ELSE
          v_svg := v_svg || '<rect x="' || r.x::text || '" y="' || r.y::text
            || '" width="' || r.width::text || '" height="' || r.height::text
            || '" fill="#ddd"' || v_attrs || v_transform || '/>';
        END IF;
      WHEN 'path' THEN
        IF r.props ? 'd' THEN
          v_svg := v_svg || '<path d="' || pgv.esc(r.props->>'d') || '"'
            || CASE WHEN r.fill IS NOT NULL THEN ' fill="' || pgv.esc(r.fill) || '"' ELSE ' fill="none"' END
            || CASE WHEN r.stroke IS NOT NULL THEN ' stroke="' || pgv.esc(r.stroke) || '"' ELSE '' END
            || v_attrs || v_transform || '/>';
        END IF;
      ELSE
        NULL;
    END CASE;
  END LOOP;

  RETURN '<svg xmlns="http://www.w3.org/2000/svg" xmlns:xlink="http://www.w3.org/1999/xlink" viewBox="0 0 '
    || v_c.width::text || ' ' || v_c.height::text || '">'
    || CASE WHEN v_defs != '' THEN '<defs>' || v_defs || '</defs>' ELSE '' END
    || v_svg || '</svg>';
END;
$function$;
COMMENT ON FUNCTION document.canvas_render_svg_mini(uuid) IS 'Render SVG with contain (logos/SVG) vs cover (photos) + clipPath crop';

CREATE OR REPLACE FUNCTION document.company_info()
 RETURNS document.company
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_row document.company;
BEGIN
  SELECT * INTO v_row
  FROM document.company
  WHERE tenant_id = current_setting('app.tenant_id', true)
  LIMIT 1;
  RETURN v_row;
END;
$function$;
COMMENT ON FUNCTION document.company_info() IS 'Return company info for current tenant (internal utility)';

CREATE OR REPLACE FUNCTION document.current_user_id()
 RETURNS text
 LANGUAGE sql
 STABLE
AS $function$
  SELECT CASE
    WHEN NULLIF(current_setting('app.user_id', true), '') IS NOT NULL
      THEN current_setting('app.user_id', true)
    ELSE 'dev'
  END;
$function$;
COMMENT ON FUNCTION document.current_user_id() IS 'Resolve current user ID: app.user_id or ''dev'' fallback';

CREATE OR REPLACE FUNCTION document.data_canvases(p_params jsonb DEFAULT '{}'::jsonb)
 RETURNS jsonb
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_category text := NULLIF(trim(COALESCE(p_params->>'p_category', '')), '');
  v_q        text := NULLIF(trim(COALESCE(p_params->>'q', '')), '');
  v_offset   int  := coalesce((p_params->>'_offset')::int, 0);
  v_size     int  := coalesce((p_params->>'_size')::int, 20);
  v_rows     jsonb;
  v_has_more boolean;
BEGIN
  SELECT coalesce(jsonb_agg(row), '[]') INTO v_rows
  FROM (
    SELECT jsonb_build_array(
      c.id,
      c.name,
      c.format || ' ' || c.orientation,
      c.category,
      (SELECT count(*) FROM document.element e WHERE e.canvas_id = c.id)::int,
      to_char(c.updated_at, 'DD/MM/YYYY')
    ) AS row
    FROM document.canvas c
    WHERE c.tenant_id = current_setting('app.tenant_id', true)
      AND (v_category IS NULL OR c.category = v_category)
      AND (v_q IS NULL OR c.name ILIKE '%' || v_q || '%')
    ORDER BY c.updated_at DESC
    LIMIT v_size + 1 OFFSET v_offset
  ) sub;

  v_has_more := jsonb_array_length(v_rows) > v_size;
  IF v_has_more THEN
    v_rows := v_rows - v_size;
  END IF;

  RETURN jsonb_build_object('rows', v_rows, 'has_more', v_has_more);
END;
$function$;
COMMENT ON FUNCTION document.data_canvases(jsonb) IS 'Data provider for pgv.table(): canvas list with filters and pagination';

CREATE OR REPLACE FUNCTION document.data_documents(p_params jsonb DEFAULT '{}'::jsonb)
 RETURNS jsonb
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_doc_type text   := NULLIF(trim(COALESCE(p_params->>'p_doc_type', '')), '');
  v_status   text   := NULLIF(trim(COALESCE(p_params->>'p_status', '')), '');
  v_q        text   := NULLIF(trim(COALESCE(p_params->>'q', '')), '');
  v_offset   int    := coalesce((p_params->>'_offset')::int, 0);
  v_size     int    := coalesce((p_params->>'_size')::int, 20);
  v_rows     jsonb;
  v_has_more boolean;
BEGIN
  SELECT coalesce(jsonb_agg(row), '[]') INTO v_rows
  FROM (
    SELECT jsonb_build_array(
      d.id,
      d.title,
      d.doc_type,
      COALESCE(d.ref_module, '—'),
      COALESCE(d.ref_id, '—'),
      d.status,
      to_char(d.created_at, 'DD/MM/YYYY')
    ) AS row
    FROM document.document d
    WHERE d.tenant_id = current_setting('app.tenant_id', true)
      AND (v_doc_type IS NULL OR d.doc_type = v_doc_type)
      AND (v_status IS NULL OR d.status = v_status)
      AND (v_q IS NULL OR d.title ILIKE '%' || v_q || '%')
    ORDER BY d.created_at DESC
    LIMIT v_size + 1 OFFSET v_offset
  ) sub;

  v_has_more := jsonb_array_length(v_rows) > v_size;
  IF v_has_more THEN
    v_rows := v_rows - v_size;
  END IF;

  RETURN jsonb_build_object('rows', v_rows, 'has_more', v_has_more);
END;
$function$;
COMMENT ON FUNCTION document.data_documents(jsonb) IS 'Data provider for pgv.table(): document list with filters and cursor pagination';

CREATE OR REPLACE FUNCTION document.element_add(p_canvas_id uuid, p_type text, p_sort_order integer DEFAULT 0, p_props jsonb DEFAULT '{}'::jsonb)
 RETURNS uuid
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_id uuid;
BEGIN
  INSERT INTO document.element (
    canvas_id, type, sort_order,
    parent_id, name,
    x, y, width, height,
    x1, y1, x2, y2,
    cx, cy, r, rx_, ry_,
    opacity, rotation, fill, stroke, stroke_width, stroke_dasharray,
    asset_id, props, tenant_id
  ) VALUES (
    p_canvas_id, p_type, p_sort_order,
    (p_props->>'parent_id')::uuid,
    p_props->>'name',
    (p_props->>'x')::real, (p_props->>'y')::real,
    (p_props->>'width')::real, (p_props->>'height')::real,
    (p_props->>'x1')::real, (p_props->>'y1')::real,
    (p_props->>'x2')::real, (p_props->>'y2')::real,
    (p_props->>'cx')::real, (p_props->>'cy')::real,
    (p_props->>'r')::real, (p_props->>'rx')::real, (p_props->>'ry')::real,
    COALESCE((p_props->>'opacity')::real, 1),
    COALESCE((p_props->>'rotation')::real, 0),
    p_props->>'fill', p_props->>'stroke',
    (p_props->>'stroke_width')::real, p_props->>'stroke_dasharray',
    (p_props->>'asset_id')::uuid,
    p_props - ARRAY['parent_id','name','x','y','width','height','x1','y1','x2','y2',
                     'cx','cy','r','rx','ry','opacity','rotation','fill','stroke',
                     'stroke_width','stroke_dasharray','asset_id'],
    current_setting('app.tenant_id', true)
  ) RETURNING id INTO v_id;
  RETURN v_id;
END;
$function$;
COMMENT ON FUNCTION document.element_add(uuid,text,integer,jsonb) IS 'Add element to canvas, extracting typed columns from props jsonb.';

CREATE OR REPLACE FUNCTION document.element_batch_update(p_updates jsonb)
 RETURNS integer
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_item jsonb;
  v_count int := 0;
BEGIN
  FOR v_item IN SELECT * FROM jsonb_array_elements(p_updates)
  LOOP
    PERFORM document.element_update(
      (v_item->>'id')::uuid,
      v_item - 'id'
    );
    v_count := v_count + 1;
  END LOOP;
  RETURN v_count;
END;
$function$;
COMMENT ON FUNCTION document.element_batch_update(jsonb) IS 'Batch update multiple elements from a JSON array';

CREATE OR REPLACE FUNCTION document.element_delete(p_element_id uuid)
 RETURNS jsonb
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_info jsonb;
BEGIN
  SELECT jsonb_build_object('id', id, 'name', name, 'type', type) INTO v_info
  FROM document.element
  WHERE id = p_element_id
    AND tenant_id = current_setting('app.tenant_id', true);

  IF v_info IS NULL THEN
    RETURN NULL;
  END IF;

  -- CASCADE deletes children via FK
  DELETE FROM document.element WHERE id = p_element_id;

  RETURN v_info;
END;
$function$;
COMMENT ON FUNCTION document.element_delete(uuid) IS 'Delete element and cascade children, return deleted info';

CREATE OR REPLACE FUNCTION document.element_move(p_element_id uuid, p_dx real, p_dy real)
 RETURNS integer
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_count int := 0;
BEGIN
  -- Recursive CTE: collect this element + all descendants
  WITH RECURSIVE tree AS (
    SELECT id, type FROM document.element WHERE id = p_element_id
    UNION ALL
    SELECT e.id, e.type FROM document.element e JOIN tree t ON e.parent_id = t.id
  )
  -- Update leaf elements based on their type
  UPDATE document.element e SET
    x  = CASE WHEN e.type IN ('text','rect','image') THEN e.x + p_dx ELSE e.x END,
    y  = CASE WHEN e.type IN ('text','rect','image') THEN e.y + p_dy ELSE e.y END,
    x1 = CASE WHEN e.type = 'line' THEN e.x1 + p_dx ELSE e.x1 END,
    y1 = CASE WHEN e.type = 'line' THEN e.y1 + p_dy ELSE e.y1 END,
    x2 = CASE WHEN e.type = 'line' THEN e.x2 + p_dx ELSE e.x2 END,
    y2 = CASE WHEN e.type = 'line' THEN e.y2 + p_dy ELSE e.y2 END,
    cx = CASE WHEN e.type IN ('circle','ellipse') THEN e.cx + p_dx ELSE e.cx END,
    cy = CASE WHEN e.type IN ('circle','ellipse') THEN e.cy + p_dy ELSE e.cy END
  FROM tree t
  WHERE e.id = t.id AND t.type != 'group';

  GET DIAGNOSTICS v_count = ROW_COUNT;
  RETURN v_count;
END;
$function$;
COMMENT ON FUNCTION document.element_move(uuid,real,real) IS 'Move element (or recursively all children of a group) by dx/dy offset';

CREATE OR REPLACE FUNCTION document.element_update(p_element_id uuid, p_props_patch jsonb)
 RETURNS void
 LANGUAGE plpgsql
AS $function$
BEGIN
  UPDATE document.element SET
    x            = COALESCE((p_props_patch->>'x')::real, x),
    y            = COALESCE((p_props_patch->>'y')::real, y),
    width        = COALESCE((p_props_patch->>'width')::real, width),
    height       = COALESCE((p_props_patch->>'height')::real, height),
    x1           = COALESCE((p_props_patch->>'x1')::real, x1),
    y1           = COALESCE((p_props_patch->>'y1')::real, y1),
    x2           = COALESCE((p_props_patch->>'x2')::real, x2),
    y2           = COALESCE((p_props_patch->>'y2')::real, y2),
    cx           = COALESCE((p_props_patch->>'cx')::real, cx),
    cy           = COALESCE((p_props_patch->>'cy')::real, cy),
    r            = COALESCE((p_props_patch->>'r')::real, r),
    rx_          = COALESCE((p_props_patch->>'rx')::real, rx_),
    ry_          = COALESCE((p_props_patch->>'ry')::real, ry_),
    opacity      = COALESCE((p_props_patch->>'opacity')::real, opacity),
    rotation     = COALESCE((p_props_patch->>'rotation')::real, rotation),
    fill         = COALESCE(p_props_patch->>'fill', fill),
    stroke       = COALESCE(p_props_patch->>'stroke', stroke),
    stroke_width = COALESCE((p_props_patch->>'stroke_width')::real, stroke_width),
    stroke_dasharray = COALESCE(p_props_patch->>'stroke_dasharray', stroke_dasharray),
    name         = COALESCE(p_props_patch->>'name', name),
    sort_order   = COALESCE((p_props_patch->>'sort_order')::int, sort_order),
    parent_id    = CASE WHEN p_props_patch ? 'parent_id' THEN (p_props_patch->>'parent_id')::uuid ELSE parent_id END,
    props        = props || (p_props_patch - ARRAY['x','y','width','height','x1','y1','x2','y2',
                   'cx','cy','r','rx','ry','opacity','rotation','fill','stroke',
                   'stroke_width','stroke_dasharray','name','sort_order','parent_id','asset_id'])
  WHERE id = p_element_id
    AND tenant_id = current_setting('app.tenant_id', true);
END;
$function$;
COMMENT ON FUNCTION document.element_update(uuid,jsonb) IS 'Patch element: merge typed columns + JSONB props';

CREATE OR REPLACE FUNCTION document.get_brand_guide(p_id uuid)
 RETURNS document.brand_guide
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_row document.brand_guide;
BEGIN
  SELECT * INTO v_row FROM document.brand_guide
  WHERE id = p_id AND tenant_id = current_setting('app.tenant_id', true);
  RETURN v_row;
END;
$function$;
COMMENT ON FUNCTION document.get_brand_guide(uuid) IS 'Get a brand guide by ID';

CREATE OR REPLACE FUNCTION document.get_brand_guides(p_params jsonb DEFAULT '{}'::jsonb)
 RETURNS text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_body text;
  v_cards text[];
  v_swatches text;
  r record;
BEGIN
  v_body := '';
  v_cards := ARRAY[]::text[];

  FOR r IN
    SELECT * FROM document.brand_guide
    WHERE tenant_id = current_setting('app.tenant_id', true)
    ORDER BY name
  LOOP
    -- Color swatches preview
    v_swatches := '<div class="grid">'
      || '<div><small>Principal</small><br><svg width="40" height="20"><rect width="40" height="20" fill="' || pgv.esc(r.primary_color) || '" rx="3"/></svg></div>'
      || '<div><small>Secondaire</small><br><svg width="40" height="20"><rect width="40" height="20" fill="' || pgv.esc(COALESCE(r.secondary_color, '#fff')) || '" rx="3" stroke="#ddd"/></svg></div>'
      || CASE WHEN r.accent_color IS NOT NULL THEN '<div><small>Accent</small><br><svg width="40" height="20"><rect width="40" height="20" fill="' || pgv.esc(r.accent_color) || '" rx="3"/></svg></div>' ELSE '' END
      || '<div><small>Texte</small><br><svg width="40" height="20"><rect width="40" height="20" fill="' || pgv.esc(COALESCE(r.text_color, '#000')) || '" rx="3"/></svg></div>'
      || '</div>'
      || '<p><small>' || pgv.esc(r.font_title) || ' ' || pgv.esc(r.font_title_weight) || ' ' || r.font_title_size::text || 'mm · '
      || pgv.esc(r.font_body) || ' ' || pgv.esc(r.font_body_weight) || ' ' || r.font_body_size::text || 'mm</small></p>';

    v_cards := v_cards || pgv.card(r.name, v_swatches);
  END LOOP;

  IF cardinality(v_cards) = 0 THEN
    v_body := pgv.empty(pgv.t('document.empty_no_brand_guide'), pgv.t('document.empty_first_brand_guide'));
  ELSE
    v_body := pgv.grid(VARIADIC v_cards);
  END IF;

  RETURN v_body;
END;
$function$;
COMMENT ON FUNCTION document.get_brand_guides(jsonb) IS 'Brand guides list page with color swatch previews';

CREATE OR REPLACE FUNCTION document.get_canvas(p_id uuid)
 RETURNS text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_c document.canvas;
  v_body text;
  v_svg text;
  v_elem_cnt int;
  v_rows text[];
  v_indent text;
  v_pos text;
  v_dims text;
  r record;
BEGIN
  SELECT * INTO v_c FROM document.canvas WHERE id = p_id AND tenant_id = current_setting('app.tenant_id', true);
  IF v_c IS NULL THEN
    RETURN pgv.empty('Canvas introuvable');
  END IF;

  SELECT count(*)::int INTO v_elem_cnt FROM document.element WHERE canvas_id = p_id;

  v_body := pgv.breadcrumb(VARIADIC ARRAY['Documents', '/', v_c.name]);

  v_body := v_body || '<p><small>'
    || v_c.format || ' ' || v_c.orientation
    || ' · ' || v_c.width::int::text || '×' || v_c.height::int::text || 'mm'
    || ' · ' || v_elem_cnt::text || ' éléments'
    || ' · ' || pgv.esc(v_c.category)
    || '</small></p>';

  v_svg := document.canvas_render_svg_mini(p_id);
  IF v_svg IS NOT NULL THEN
    v_body := v_body || pgv.svg_canvas(v_svg, '{"height":"70vh"}'::jsonb);
  END IF;

  v_rows := ARRAY[]::text[];
  FOR r IN
    SELECT e.sort_order, e.type, e.name, e.parent_id,
           e.x, e.y, e.width, e.height,
           e.x1, e.y1, e.x2, e.y2,
           e.cx, e.cy, e.r, e.rx_, e.ry_,
           e.fill
    FROM document.element e
    WHERE e.canvas_id = p_id
    ORDER BY e.sort_order
  LOOP
    v_indent := CASE WHEN r.parent_id IS NOT NULL THEN '└─ ' ELSE '' END;
    v_pos := CASE r.type
      WHEN 'text' THEN COALESCE(r.x::int::text, '') || ',' || COALESCE(r.y::int::text, '')
      WHEN 'rect' THEN COALESCE(r.x::int::text, '') || ',' || COALESCE(r.y::int::text, '')
      WHEN 'image' THEN COALESCE(r.x::int::text, '') || ',' || COALESCE(r.y::int::text, '')
      WHEN 'line' THEN COALESCE(r.x1::int::text, '') || ',' || COALESCE(r.y1::int::text, '') || '->' || COALESCE(r.x2::int::text, '') || ',' || COALESCE(r.y2::int::text, '')
      WHEN 'circle' THEN COALESCE(r.cx::int::text, '') || ',' || COALESCE(r.cy::int::text, '')
      WHEN 'ellipse' THEN COALESCE(r.cx::int::text, '') || ',' || COALESCE(r.cy::int::text, '')
      ELSE '—'
    END;
    v_dims := CASE r.type
      WHEN 'rect' THEN COALESCE(r.width::int::text, '') || '×' || COALESCE(r.height::int::text, '')
      WHEN 'image' THEN COALESCE(r.width::int::text, '') || '×' || COALESCE(r.height::int::text, '')
      WHEN 'circle' THEN 'r=' || COALESCE(r.r::int::text, '')
      WHEN 'ellipse' THEN COALESCE(r.rx_::int::text, '') || '×' || COALESCE(r.ry_::int::text, '')
      ELSE '—'
    END;
    v_rows := v_rows || ARRAY[
      r.sort_order::text,
      v_indent || r.type,
      COALESCE(r.name, '—'),
      v_pos,
      v_dims,
      COALESCE(r.fill, '—')
    ];
  END LOOP;

  IF cardinality(v_rows) > 0 THEN
    v_body := v_body || '<h3>Éléments</h3>'
      || pgv.md_table(ARRAY['#', 'Type', 'Nom', 'Position', 'Dimensions', 'Fill'], v_rows, 20);
  END IF;

  -- Actions
  v_body := v_body || '<p>'
    || pgv.action('post_canvas_duplicate', 'Dupliquer', jsonb_build_object('p_source_id', p_id), 'Dupliquer ce canvas ?', 'outline')
    || ' '
    || pgv.action('post_canvas_delete', 'Supprimer', jsonb_build_object('p_id', p_id), 'Supprimer ce canvas et tous ses éléments ?', 'danger')
    || '</p>';

  RETURN v_body;
END;
$function$;
COMMENT ON FUNCTION document.get_canvas(uuid) IS 'Canvas detail page: SVG view + element table + duplicate/delete actions';

CREATE OR REPLACE FUNCTION document.get_company(p_params jsonb DEFAULT '{}'::jsonb)
 RETURNS text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_c    document.company;
  v_body text;
BEGIN
  v_c := document.company_info();

  IF v_c.id IS NULL THEN
    v_body := pgv.empty(pgv.t('document.title_company_empty'), pgv.t('document.title_company_help'));
  ELSE
    v_body := pgv.grid(VARIADIC ARRAY[
      pgv.card(pgv.t('document.field_name'), pgv.esc(v_c.name)),
      pgv.card(pgv.t('document.field_siret'), COALESCE(pgv.esc(v_c.siret), '—')),
      pgv.card(pgv.t('document.field_tva_intra'), COALESCE(pgv.esc(v_c.tva_intra), '—'))
    ]);
    v_body := v_body || pgv.grid(VARIADIC ARRAY[
      pgv.card(pgv.t('document.field_address'), COALESCE(pgv.esc(v_c.address), '—')),
      pgv.card(pgv.t('document.field_city'), COALESCE(pgv.esc(v_c.city), '—')),
      pgv.card(pgv.t('document.field_postal_code'), COALESCE(pgv.esc(v_c.postal_code), '—'))
    ]);
    v_body := v_body || pgv.grid(VARIADIC ARRAY[
      pgv.card(pgv.t('document.field_phone'), COALESCE(pgv.esc(v_c.phone), '—')),
      pgv.card(pgv.t('document.field_email'), COALESCE(pgv.esc(v_c.email), '—')),
      pgv.card(pgv.t('document.field_website'), COALESCE(pgv.esc(v_c.website), '—'))
    ]);
    IF v_c.mentions IS NOT NULL THEN
      v_body := v_body || '<blockquote>' || pgv.esc(v_c.mentions) || '</blockquote>';
    END IF;
  END IF;

  -- Edit form
  v_body := COALESCE(v_body, '') || '<h3>' || pgv.t('document.title_company') || '</h3>'
    || '<form data-rpc="post_company_save">'
    || pgv.input('p_name', 'text', pgv.t('document.field_name'), v_c.name)
    || '<div class="grid">'
    || pgv.input('p_siret', 'text', pgv.t('document.field_siret'), v_c.siret)
    || pgv.input('p_tva_intra', 'text', pgv.t('document.field_tva_intra'), v_c.tva_intra)
    || '</div>'
    || pgv.input('p_address', 'text', pgv.t('document.field_address'), v_c.address)
    || '<div class="grid">'
    || pgv.input('p_city', 'text', pgv.t('document.field_city'), v_c.city)
    || pgv.input('p_postal_code', 'text', pgv.t('document.field_postal_code'), v_c.postal_code)
    || '</div>'
    || '<div class="grid">'
    || pgv.input('p_phone', 'text', pgv.t('document.field_phone'), v_c.phone)
    || pgv.input('p_email', 'email', pgv.t('document.field_email'), v_c.email)
    || pgv.input('p_website', 'text', pgv.t('document.field_website'), v_c.website)
    || '</div>'
    || pgv.textarea('p_mentions', pgv.t('document.field_mentions'), v_c.mentions)
    || '<button type="submit">' || pgv.t('document.btn_save') || '</button>'
    || '</form>';

  RETURN v_body;
END;
$function$;
COMMENT ON FUNCTION document.get_company(jsonb) IS 'Company info page with edit form';

CREATE OR REPLACE FUNCTION document.get_editor(p_id uuid)
 RETURNS text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_c document.canvas;
BEGIN
  SELECT * INTO v_c FROM document.canvas WHERE id = p_id AND tenant_id = current_setting('app.tenant_id', true);
  IF v_c IS NULL THEN
    RETURN pgv.empty(pgv.t('document.canvas_not_found'));
  END IF;

  -- data-illustrator triggers the shell to load D3 + app.js bundle
  -- x-data="illustrator" activates the Alpine bridge component
  RETURN '<div data-illustrator="' || p_id::text || '">'

    -- Loader
    || '<div class="loader" id="loader" x-show="phase === ''loading''" x-transition.opacity><div class="loader-content">'
    || '<h1 class="loader-title">' || pgv.esc(v_c.name) || '</h1>'
    || '<div class="loader-line"><div class="loader-pulse"></div></div>'
    || '</div></div>'

    -- Menu bar
    || '<header class="menu-bar" id="menuBar">'
    || '<div class="menu-section menu-section--brand"><span class="menu-app-name" x-text="canvas?.name || ''-''">' || pgv.esc(v_c.name) || '</span><div class="status-dot" id="statusDot"></div></div>'
    || '<div class="menu-sep"></div>'

    -- Doc selector
    || '<div class="menu-section menu-section--doc"><button class="doc-selector" @click="toggleDocDropdown()"><span class="doc-selector-label" x-text="canvas?.name || ''Aucun document''"></span><svg class="doc-selector-chevron" viewBox="0 0 16 16" fill="none" stroke="currentColor" stroke-width="2"><path d="M4 6l4 4 4-4"/></svg></button>'
    || '<div class="doc-dropdown" x-show="docDropdownOpen" @click.outside="docDropdownOpen=false" x-transition>'
    || '<template x-for="doc in docList" :key="doc.id"><button class="doc-dropdown-item" @click="loadDoc(doc.id)" x-text="doc.name"></button></template>'
    || '</div></div>'
    || '<div class="menu-sep"></div>'

    -- Undo/Redo/Save
    || '<div class="menu-section"><div class="menu-btn-group">'
    || '<button class="menu-btn" @click="undo()" data-tooltip="Annuler"><svg viewBox="0 0 16 16" fill="none" stroke="currentColor" stroke-width="1.5"><path d="M3 7h7a3 3 0 0 1 0 6H9"/><path d="M6 4L3 7l3 3"/></svg></button>'
    || '<button class="menu-btn" @click="redo()" data-tooltip="Refaire"><svg viewBox="0 0 16 16" fill="none" stroke="currentColor" stroke-width="1.5"><path d="M13 7H6a3 3 0 0 0 0 6h1"/><path d="M10 4l3 3-3 3"/></svg></button>'
    || '</div></div>'
    || '<div class="menu-sep"></div>'

    -- Toggle buttons
    || '<div class="menu-section"><div class="menu-btn-group">'
    || '<button class="menu-btn" :class="{active: snapEnabled}" @click="toggleSnap()" data-tooltip="Magnetisme"><svg viewBox="0 0 16 16" fill="none" stroke="currentColor" stroke-width="1.5"><path d="M8 1v14M1 8h14"/><circle cx="8" cy="8" r="3"/></svg></button>'
    || '<button class="menu-btn" :class="{active: showBleed}" @click="toggleShowBleed()" data-tooltip="Fond perdu"><svg viewBox="0 0 16 16" fill="none" stroke="currentColor" stroke-width="1.5"><rect x="2" y="2" width="12" height="12" rx="1" stroke-dasharray="2 1.5"/><rect x="4" y="4" width="8" height="8" rx="0.5"/></svg></button>'
    || '<button class="menu-btn" :class="{active: showNames}" @click="toggleShowNames()" data-tooltip="Inspecteur"><svg viewBox="0 0 16 16" fill="none" stroke="currentColor" stroke-width="1.5"><rect x="2" y="3" width="12" height="10" rx="1"/><path d="M5 6h6M5 9h3"/></svg></button>'
    || '</div>'
    || '<button class="menu-btn" :class="{active: documentLocked}" @click="toggleLock()" data-tooltip="Verrouiller"><svg viewBox="0 0 16 16" fill="none" stroke="currentColor" stroke-width="1.5"><rect x="3" y="7" width="10" height="7" rx="1.5"/><path d="M5 7V5a3 3 0 0 1 6 0v2"/></svg></button>'
    || '</div>'
    || '<div class="menu-sep"></div>'

    -- Zoom
    || '<div class="menu-section menu-section--zoom"><span class="zoom-label" id="zoomLabel" x-text="zoomPercent"></span><input class="zoom-slider" id="zoomSlider" type="range" min="15" max="400" :value="zoom*100" @input="setZoom(+$event.target.value)" step="5"></div>'
    || '<div class="menu-spacer"></div>'

    -- Export
    || '<div class="menu-section"><button class="menu-btn menu-btn--export" data-tooltip="SVG">SVG</button><button class="menu-btn menu-btn--export" data-tooltip="PDF">PDF</button></div>'
    || '</header>'

    -- Workspace
    || '<div class="workspace" id="workspace">'

    -- Layers panel
    || '<aside class="layers-panel" x-show="!layersPanelCollapsed" x-transition>'
    || '<div class="panel-header"><span class="panel-title">Structure</span><span class="panel-count" x-text="elements.length"></span>'
    || '<button class="panel-collapse-btn" @click="toggleLayersPanel()"><svg viewBox="0 0 16 16" fill="none" stroke="currentColor" stroke-width="2"><path d="M10 4l-4 4 4 4"/></svg></button></div>'
    || '<div class="panel-body" id="panelBodyLayers"><ul class="tree" id="tree">'
    || '<template x-for="el in elements" :key="el.id"><li @click.stop="selectElement(el.id, $event.metaKey || $event.ctrlKey)" :class="{active: selectedIds.includes(el.id)}" x-text="el.name || el.type" class="tree-item"></li></template>'
    || '</ul></div>'
    || '<div class="layers-actions">'
    || '<button class="action-btn" @click="deleteSelected()" :disabled="selectedIds.length===0" data-tooltip="Supprimer"><svg viewBox="0 0 16 16" fill="none" stroke="currentColor" stroke-width="1.5"><path d="M3 4h10M6 4V3a1 1 0 0 1 1-1h2a1 1 0 0 1 1 1v1m2 0v9a1 1 0 0 1-1 1H5a1 1 0 0 1-1-1V4h10z"/></svg></button>'
    || '<button class="action-btn" @click="duplicateSelected()" :disabled="selectedIds.length===0" data-tooltip="Dupliquer"><svg viewBox="0 0 16 16" fill="none" stroke="currentColor" stroke-width="1.5"><rect x="5" y="5" width="8" height="8" rx="1"/><path d="M3 11V3a1 1 0 0 1 1-1h8"/></svg></button>'
    || '</div></aside>'

    -- Resize handle + Canvas
    || '<div class="resize-handle-v" id="resizeHandleL"></div>'
    || '<main class="canvas-viewport" id="canvasViewport"><div class="svg-wrap"><svg id="canvas"></svg></div></main>'
    || '<div class="resize-handle-v" id="resizeHandleR"></div>'

    -- Props panel
    || '<aside class="properties-panel" x-show="!propsPanelCollapsed" x-transition>'
    || '<div class="panel-header"><span class="panel-title" x-text="selectedElement ? (selectedElement.name || selectedElement.type) : ''Proprietes''"></span>'
    || '<button class="panel-collapse-btn" @click="togglePropsPanel()"><svg viewBox="0 0 16 16" fill="none" stroke="currentColor" stroke-width="2"><path d="M6 4l4 4-4 4"/></svg></button></div>'
    || '<div class="panel-body" id="propsContent">'
    || '<template x-if="selectedElement">'
    || '<div class="props-form">'
    || '<label>X <input type="number" :value="selectedElement.x" @change="updateElement(selectedElement.id, {x: +$event.target.value})" class="prop-input"></label>'
    || '<label>Y <input type="number" :value="selectedElement.y" @change="updateElement(selectedElement.id, {y: +$event.target.value})" class="prop-input"></label>'
    || '<label>W <input type="number" :value="selectedElement.width" @change="updateElement(selectedElement.id, {width: +$event.target.value})" class="prop-input"></label>'
    || '<label>H <input type="number" :value="selectedElement.height" @change="updateElement(selectedElement.id, {height: +$event.target.value})" class="prop-input"></label>'
    || '<label>Fill <input type="color" :value="selectedElement.fill || ''#000000''" @input="updateElement(selectedElement.id, {fill: $event.target.value})" class="prop-color"></label>'
    || '<label>Opacity <input type="range" min="0" max="1" step="0.05" :value="selectedElement.opacity" @input="updateElement(selectedElement.id, {opacity: +$event.target.value})" class="prop-range"></label>'
    || '</div>'
    || '</template>'
    || '<template x-if="!selectedElement"><p class="props-empty">Selectionnez un element</p></template>'
    || '</div></aside>'

    || '</div>'

    -- Photo library
    || '<div class="resize-handle-h" id="resizeHandleH"></div>'
    || '<div class="photo-library" x-show="!photoCollapsed">'
    || '<div class="photo-header"><button class="photo-collapse-btn" @click="togglePhotoPanel()"><svg viewBox="0 0 12 12" fill="none" stroke="currentColor" stroke-width="1.5" stroke-linecap="round"><path d="M2.5 4l3.5 3.5L9.5 4"/></svg></button><span class="photo-title">Bibliotheque</span><span class="photo-count" x-text="assets.length"></span></div>'
    || '<div class="photo-strip" id="photoGrid">'
    || '<template x-for="a in assets" :key="a.id"><div class="photo-thumb" @click="/* TODO: insert asset */" :title="a.filename"><img :src="a.thumb_path || a.path" :alt="a.filename"></div></template>'
    || '</div></div>'

    -- Toast
    || '<div x-show="toast" x-transition.opacity class="toast" :class="''toast-'' + (toast?.level || ''info'')" x-text="toast?.text"></div>'

    -- Image editor modal (keep legacy IDs for now)
    || '<div class="ie-overlay" id="imageEditorOverlay"><div class="ie-card"><div class="ie-header"><span class="ie-header-title">Modifier l''image</span><span class="ie-header-path"></span><button class="ie-close">&times;</button></div><div class="ie-body"><div class="ie-preview" id="iePreview"></div><div class="ie-controls" id="ieControls"></div></div><div class="ie-footer"><button class="ie-btn" id="ieCancel">Annuler</button><button class="ie-btn ie-btn-primary" id="ieApply">Appliquer</button></div></div></div>'

    || '</div>';
END;
$function$;
COMMENT ON FUNCTION document.get_editor(uuid) IS 'Illustrator workspace with Alpine.js declarative markup — loaded in pgView shell';

CREATE OR REPLACE FUNCTION document.get_index(p_params jsonb DEFAULT '{}'::jsonb)
 RETURNS text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_total_tpl  int;
  v_total_doc  int;
  v_total_cvs  int;
  v_draft      int;
  v_body       text;
  v_cards      text[];
  v_svg        text;
  v_elem_cnt   int;
  v_href       text;
  r            record;
BEGIN
  SELECT count(*)::int INTO v_total_tpl FROM document.template WHERE tenant_id = current_setting('app.tenant_id', true);
  SELECT count(*)::int INTO v_total_doc FROM document.document WHERE tenant_id = current_setting('app.tenant_id', true);
  SELECT count(*)::int INTO v_total_cvs FROM document.canvas WHERE tenant_id = current_setting('app.tenant_id', true);
  SELECT count(*)::int INTO v_draft FROM document.document WHERE tenant_id = current_setting('app.tenant_id', true) AND status = 'draft';

  v_body := pgv.grid(VARIADIC ARRAY[
    pgv.stat(pgv.t('document.stat_canvases'), v_total_cvs::text),
    pgv.stat(pgv.t('document.stat_templates'), v_total_tpl::text),
    pgv.stat(pgv.t('document.stat_documents'), v_total_doc::text),
    pgv.stat(pgv.t('document.stat_draft'), v_draft::text)
  ]);

  -- Canvas section: grid of clickable cards with SVG miniature
  v_body := v_body || '<h3>' || pgv.t('document.title_canvases') || '</h3>';
  IF v_total_cvs = 0 THEN
    v_body := v_body || pgv.empty(pgv.t('document.empty_no_canvas'), pgv.t('document.empty_first_canvas'));
  ELSE
    v_cards := ARRAY[]::text[];
    FOR r IN
      SELECT c.id, c.name, c.format, c.orientation, c.category
      FROM document.canvas c
      WHERE c.tenant_id = current_setting('app.tenant_id', true)
      ORDER BY c.updated_at DESC
    LOOP
      v_svg := document.canvas_render_svg_mini(r.id);
      SELECT count(*)::int INTO v_elem_cnt FROM document.element WHERE canvas_id = r.id;
      v_href := pgv.call_ref('get_editor', jsonb_build_object('p_id', r.id));

      v_cards := v_cards || (
        '<a href="' || v_href || '">'
        || pgv.card(
          r.name,
          CASE WHEN v_elem_cnt = 0
            THEN pgv.empty(pgv.t('document.empty_no_canvas'))
            ELSE pgv.svg_canvas(v_svg, '{"height":"200px","toolbar":false}'::jsonb)
          END,
          r.format || ' ' || r.orientation || ' · ' || v_elem_cnt || ' éléments'
        )
        || '</a>'
      );
    END LOOP;
    v_body := v_body || pgv.grid(VARIADIC v_cards);
  END IF;

  -- Documents section
  IF v_total_doc > 0 THEN
    v_body := v_body || '<h3>' || pgv.t('document.stat_documents') || '</h3>';
    v_body := v_body || pgv.table(jsonb_build_object(
      'rpc',     'data_documents',
      'schema',  'document',
      'filters', jsonb_build_array(
        jsonb_build_object('name','p_doc_type','type','select','label', pgv.t('document.field_doc_type'),
          'options', jsonb_build_array(
            jsonb_build_array('', pgv.t('document.filter_all')),
            jsonb_build_array('facture', pgv.t('document.type_facture')),
            jsonb_build_array('devis', pgv.t('document.type_devis')),
            jsonb_build_array('bon_commande', pgv.t('document.type_bon_commande')),
            jsonb_build_array('bon_livraison', pgv.t('document.type_bon_livraison')),
            jsonb_build_array('avoir', pgv.t('document.type_avoir')))),
        jsonb_build_object('name','p_status','type','select','label', pgv.t('document.field_status'),
          'options', jsonb_build_array(
            jsonb_build_array('', pgv.t('document.filter_all')),
            jsonb_build_array('draft', pgv.t('document.status_draft')),
            jsonb_build_array('generated', pgv.t('document.status_generated')),
            jsonb_build_array('signed', pgv.t('document.status_signed')),
            jsonb_build_array('archived', pgv.t('document.status_archived')))),
        jsonb_build_object('name','q','type','search','label', pgv.t('document.field_search'))
      ),
      'cols', jsonb_build_array(
        jsonb_build_object('key','id','label','#','hidden',true),
        jsonb_build_object('key','title','label', pgv.t('document.col_title')),
        jsonb_build_object('key','doc_type','label', pgv.t('document.col_doc_type')),
        jsonb_build_object('key','ref_module','label', pgv.t('document.col_module')),
        jsonb_build_object('key','ref_id','label', pgv.t('document.col_ref')),
        jsonb_build_object('key','status','label', pgv.t('document.col_status'),'class','pgv-col-badge'),
        jsonb_build_object('key','created','label', pgv.t('document.col_created'))
      ),
      'page_size', 20
    ));
  END IF;

  RETURN v_body;
END;
$function$;
COMMENT ON FUNCTION document.get_index(jsonb) IS 'Document dashboard: stats + clickable canvas cards with SVG miniature + document table';

CREATE OR REPLACE FUNCTION document.get_template(p_id uuid)
 RETURNS document.template
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_row document.template;
BEGIN
  SELECT * INTO v_row
  FROM document.template
  WHERE id = p_id
    AND tenant_id = current_setting('app.tenant_id', true);
  RETURN v_row;
END;
$function$;
COMMENT ON FUNCTION document.get_template(uuid) IS 'Get a single template by ID';

CREATE OR REPLACE FUNCTION document.get_templates(p_params jsonb DEFAULT '{}'::jsonb)
 RETURNS text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_total int;
  v_rows  text[];
  v_body  text;
  r       record;
BEGIN
  SELECT count(*)::int INTO v_total FROM document.template WHERE tenant_id = current_setting('app.tenant_id', true);

  v_body := pgv.grid(VARIADIC ARRAY[
    pgv.stat(pgv.t('document.stat_templates'), v_total::text)
  ]);

  IF v_total = 0 THEN
    v_body := v_body || pgv.empty(pgv.t('document.empty_no_template'), pgv.t('document.empty_first_template'));
  ELSE
    v_rows := ARRAY[]::text[];
    FOR r IN
      SELECT t.id, t.name, t.doc_type, t.format, t.orientation, t.is_default, t.version, t.created_at
      FROM document.template t
      WHERE t.tenant_id = current_setting('app.tenant_id', true)
      ORDER BY t.doc_type, t.name
    LOOP
      v_rows := v_rows || ARRAY[
        pgv.esc(r.name),
        r.doc_type,
        r.format || ' ' || r.orientation,
        CASE WHEN r.is_default THEN pgv.t('document.yes') ELSE pgv.t('document.no') END,
        r.version::text,
        to_char(r.created_at, 'DD/MM/YYYY')
      ];
    END LOOP;

    v_body := v_body || pgv.md_table(
      ARRAY[pgv.t('document.col_name'), pgv.t('document.col_doc_type'), pgv.t('document.col_format'), pgv.t('document.col_default'), pgv.t('document.col_version'), pgv.t('document.col_created')],
      v_rows,
      20
    );
  END IF;

  RETURN v_body;
END;
$function$;
COMMENT ON FUNCTION document.get_templates(jsonb) IS 'Templates list page';

CREATE OR REPLACE FUNCTION document.group_add_member(p_group_id uuid, p_element_id uuid)
 RETURNS void
 LANGUAGE plpgsql
AS $function$
BEGIN
  UPDATE document.element
  SET parent_id = p_group_id
  WHERE id = p_element_id
    AND tenant_id = current_setting('app.tenant_id', true);
END;
$function$;
COMMENT ON FUNCTION document.group_add_member(uuid,uuid) IS 'Add an element to a group';

CREATE OR REPLACE FUNCTION document.group_create(p_canvas_id uuid, p_element_ids uuid[], p_name text DEFAULT NULL::text)
 RETURNS uuid
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_parent uuid;
  v_group_id uuid;
  v_max_order int;
BEGIN
  -- Verify all elements are siblings (same parent_id)
  SELECT DISTINCT parent_id INTO STRICT v_parent
  FROM document.element
  WHERE id = ANY(p_element_ids) AND canvas_id = p_canvas_id;

  -- Get max sort_order for positioning
  SELECT COALESCE(max(sort_order), 0) INTO v_max_order
  FROM document.element WHERE canvas_id = p_canvas_id;

  -- Create group element with same parent
  INSERT INTO document.element (canvas_id, type, parent_id, sort_order, name)
  VALUES (p_canvas_id, 'group', v_parent, v_max_order + 1, p_name)
  RETURNING id INTO v_group_id;

  -- Reparent elements into the group
  UPDATE document.element
  SET parent_id = v_group_id
  WHERE id = ANY(p_element_ids) AND canvas_id = p_canvas_id;

  RETURN v_group_id;

EXCEPTION WHEN too_many_rows THEN
  RAISE EXCEPTION 'Cannot group elements with different parents';
END;
$function$;
COMMENT ON FUNCTION document.group_create(uuid,uuid[],text) IS 'Group sibling elements into a new group element';

CREATE OR REPLACE FUNCTION document.group_dissolve(p_group_id uuid)
 RETURNS integer
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_parent uuid;
  v_count int;
BEGIN
  -- Get parent of the group
  SELECT parent_id INTO v_parent
  FROM document.element
  WHERE id = p_group_id AND type = 'group'
    AND tenant_id = current_setting('app.tenant_id', true);

  IF NOT FOUND THEN
    RAISE EXCEPTION 'Group not found: %', p_group_id;
  END IF;

  -- Reparent children to the group's parent
  UPDATE document.element
  SET parent_id = v_parent
  WHERE parent_id = p_group_id;
  GET DIAGNOSTICS v_count = ROW_COUNT;

  -- Delete the group element
  DELETE FROM document.element WHERE id = p_group_id;

  RETURN v_count;
END;
$function$;
COMMENT ON FUNCTION document.group_dissolve(uuid) IS 'Dissolve group: reparent children to group''s parent, delete group';

CREATE OR REPLACE FUNCTION document.group_remove_member(p_element_id uuid)
 RETURNS void
 LANGUAGE plpgsql
AS $function$
BEGIN
  UPDATE document.element
  SET parent_id = NULL
  WHERE id = p_element_id
    AND tenant_id = current_setting('app.tenant_id', true);
END;
$function$;
COMMENT ON FUNCTION document.group_remove_member(uuid) IS 'Remove an element from its group (set parent_id to NULL)';

